// // This module performs a barrel shift operation on a 4-bit input A using a 2-bit control signal B. When B=00, the output Y is the same as A. When B=01, Y is the result of shifting A to the right by one position. When B=10, Y is the result of shifting A to the left by one position. When B=11, Y is the result of shifting A to the right by two positions.
module top_module(
    input [3:0] A,
    input [1:0] B,
    output reg [3:0] Y
);always @(*) begin
        case (B)
            2'b00: Y = A;
            2'b01: Y = {A[2:0], 1'b0};
            2'b10: Y = {1'b0, A[3:1]};
            2'b11: Y = {2'b00, A[3:2]};
        endcase
    end

endmodule
